"use client";

import { useQuery } from "convex/react";
import { api } from "../../../convex/_generated/api";
import { useMemo, useState } from "react";
import NavigationHeader from "@/components/NavigationHeader";
import SnippetsPageSkeleton from "./_components/SnippetsPageSkeleton";
import SnippetCard from "./_components/SnippetCard";

import { AnimatePresence, motion } from "framer-motion";
import { Grid, Layers, Search, Tag, X } from "lucide-react";

export default function SnippetsPage() {
  const snippets = useQuery(api.snippets.getSnippets);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedLanguage, setSelectedLanguage] = useState<string | null>(null);
  const [view, setView] = useState<"grid" | "list">("grid");

  if (snippets === undefined) {
    return (
      <div className="min-h-screen bg-[#0a0a0f]">
        <NavigationHeader />
        <SnippetsPageSkeleton />
      </div>
    );
  }

  const safeSnippets = Array.isArray(snippets) ? snippets : [];

  const memo = useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    const languages = [...new Set(safeSnippets.map((s) => s.language))];
    const popularLanguages = languages.slice(0, 6);

    const filteredSnippets = safeSnippets.filter((snippet) => {
      const matchesSearch =
        snippet.title.toLowerCase().includes(q) ||
        snippet.language.toLowerCase().includes(q) ||
        snippet.userName.toLowerCase().includes(q);

      const matchesLanguage =
        !selectedLanguage || snippet.language === selectedLanguage;

      return matchesSearch && matchesLanguage;
    });

    return { popularLanguages, filteredSnippets };
  }, [safeSnippets, searchQuery, selectedLanguage]);

  const { popularLanguages, filteredSnippets } = memo;

  return (
    <div className="min-h-screen bg-[#0a0a0f]">
      <NavigationHeader />

      {/* soft background glow */}
      <div className="pointer-events-none fixed inset-0">
        <div className="absolute -top-40 left-1/2 -translate-x-1/2 h-[420px] w-[900px] rounded-full bg-gradient-to-r from-blue-500/18 to-purple-500/18 blur-3xl opacity-40" />
      </div>

      <div className="relative max-w-7xl mx-auto px-4 py-8">
        {/* Top row */}
        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-6">
          <div>
            <h1 className="text-2xl md:text-3xl font-semibold text-white">
              Snippets
            </h1>
            <p className="text-sm text-gray-400 mt-1">
              Search by title, language, or author
            </p>
          </div>

          <div className="flex items-center gap-3">
            <span className="text-sm text-gray-400">
              {filteredSnippets.length} found
            </span>

            {/* view toggle */}
            <div className="flex items-center gap-1 p-1 rounded-xl bg-white/5 ring-1 ring-white/10">
              <button
                onClick={() => setView("grid")}
                className={`p-2 rounded-lg transition ${
                  view === "grid"
                    ? "bg-blue-500/20 text-blue-300"
                    : "text-gray-400 hover:bg-white/10"
                }`}
                title="Grid"
              >
                <Grid className="w-4 h-4" />
              </button>

              <button
                onClick={() => setView("list")}
                className={`p-2 rounded-lg transition ${
                  view === "list"
                    ? "bg-blue-500/20 text-blue-300"
                    : "text-gray-400 hover:bg-white/10"
                }`}
                title="List"
              >
                <Layers className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>

        {/* Search + Filters (NO BIG BORDER BOX) */}
        <div className="mb-8 space-y-4">
          {/* Search */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search snippets..."
              className="w-full h-12 pl-10 pr-3 rounded-2xl bg-white/5 ring-1 ring-white/10 text-white
                         placeholder:text-gray-500 outline-none focus:ring-2 focus:ring-blue-500/40"
            />
          </div>

          {/* Language chips + clear */}
          <div className="flex flex-wrap items-center gap-2">
            <span className="inline-flex items-center gap-2 h-10 px-3 rounded-xl bg-white/5 ring-1 ring-white/10 text-gray-300">
              <Tag className="w-4 h-4 text-gray-400" />
              Languages
            </span>

            {popularLanguages.map((lang) => (
              <button
                key={lang}
                onClick={() =>
                  setSelectedLanguage(lang === selectedLanguage ? null : lang)
                }
                className={`h-10 px-3 rounded-xl transition ring-1 flex items-center gap-2
                  ${
                    selectedLanguage === lang
                      ? "bg-blue-500/15 ring-blue-500/30 text-blue-200"
                      : "bg-white/5 ring-white/10 text-gray-300 hover:bg-white/10"
                  }`}
              >
                <img
                  src={`/${lang}.png`}
                  alt={lang}
                  className="w-4 h-4 object-contain"
                  onError={(e) => {
                    (e.currentTarget as HTMLImageElement).style.display =
                      "none";
                  }}
                />
                <span className="text-sm capitalize">{lang}</span>
              </button>
            ))}

            {(searchQuery || selectedLanguage) && (
              <button
                onClick={() => {
                  setSearchQuery("");
                  setSelectedLanguage(null);
                }}
                className="h-10 px-3 rounded-xl bg-white/5 ring-1 ring-white/10 text-gray-300 hover:bg-white/10 transition inline-flex items-center gap-2"
              >
                <X className="w-4 h-4" />
                Clear
              </button>
            )}
          </div>
        </div>

        {/* Snippets Grid */}
        <motion.div
          layout
          className={
            view === "grid"
              ? "grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-6"
              : "grid grid-cols-1 max-w-4xl mx-auto gap-6"
          }
        >
          <AnimatePresence mode="popLayout">
            {filteredSnippets.map((snippet) => (
              <SnippetCard key={snippet._id} snippet={snippet} />
            ))}
          </AnimatePresence>
        </motion.div>

        {/* Empty */}
        {filteredSnippets.length === 0 && (
          <div className="mt-16 max-w-lg mx-auto rounded-2xl bg-white/5 ring-1 ring-white/10 p-8 text-center">
            <div className="text-white text-lg font-medium">
              No snippets found
            </div>
            <p className="text-gray-400 mt-2">
              Change search text or language filter.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}
